head.script:
scwin.hid_kcomcd = "DBEX";
scwin.userId = "";
scwin.version = "202603041142";
//---------------------------------------------------------
// 전역변수
//---------------------------------------------------------   
scwin.onpageload = function () {
    let memJson = $c.data.getMemInfo();
    console.log("### onpageload :: " + JSON.stringify(memJson));
    scwin.userId = memJson.userId;
};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------    
scwin.onUdcCompleted = function () {
    setTimeout(function () {
        scwin.f_Set("INIT");
    }, 100);
}

//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------   
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": //초기화
            // $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            grp_inputGroup.setDisabled(true);
            $c.gus.cfDisableBtnOnly([btn_cancel, btn_create, btn_update, btn_save, btn_delete]);
            gr_AirExportCargoManifestPartial.setReadOnly("grid", true);
            gr_AirExportCargoManifestPartial2.setReadOnly("grid", true);
            $c.gus.cfDisableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_DisablePopUpObj()
            break;

        case "RETRIEVE":  //조회모드	
            // $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            grp_inputGroup.setDisabled(true);
            $c.gus.cfEnableBtnOnly([btn_create, btn_update, btn_delete]);
            $c.gus.cfDisableBtnOnly([btn_cancel, btn_save]);

            gr_AirExportCargoManifestPartial.setReadOnly("grid", true);
            gr_AirExportCargoManifestPartial2.setReadOnly("grid", true);
            $c.gus.cfDisableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_DisablePopUpObj()
            break;

        case "RETRIEVE2":  //조회모드	
            // $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            grp_inputGroup.setDisabled(true);
            $c.gus.cfEnableBtnOnly([btn_create]);
            $c.gus.cfDisableBtnOnly([btn_cancel, btn_save, btn_update, btn_delete]);

            gr_AirExportCargoManifestPartial.setReadOnly("grid", true);
            gr_AirExportCargoManifestPartial2.setReadOnly("grid", true);
            $c.gus.cfDisableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_DisablePopUpObj()
            break;

        case "UPDATE":
            // cfEnableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            grp_inputGroup.setDisabled(false);
            ed_senddt.setDisabled(true);
            $c.gus.cfEnableBtnOnly([btn_cancel, btn_save]);
            $c.gus.cfDisableBtnOnly([btn_create, btn_update, btn_delete]);

            gr_AirExportCargoManifestPartial.setReadOnly("grid", true);
            gr_AirExportCargoManifestPartial2.setReadOnly("grid", false);
            gr_AirExportCargoManifestPartial2.setColumnReadOnly("seq", true);
            $c.gus.cfEnableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_EnablePopUpObj();
            break;

        case "CREATE":
            // cfEnableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            grp_inputGroup.setDisabled(false);
            ed_senddt.setDisabled(true);
            $c.gus.cfEnableBtnOnly([btn_cancel, btn_save]);
            $c.gus.cfDisableBtnOnly([btn_update, btn_create, btn_delete]);

            gr_AirExportCargoManifestPartial.setReadOnly("grid", true);
            gr_AirExportCargoManifestPartial2.setReadOnly("grid", false);
            gr_AirExportCargoManifestPartial2.setColumnReadOnly("seq", true);
            $c.gus.cfEnableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_EnablePopUpObj();
            break;
    }
}

scwin.f_DisablePopUpObj = function () {
    // $c.gus.cfDisableObjects([img_bilgDt]);  	
}

scwin.f_EnablePopUpObj = function () {
    // $c.gus.cfEnableObjects([img_bilgDt]);
}

scwin.f_RetrievePartial2 = function (row) {
    var dsPatial = ds_AirExportCargoManifestPartial;

    ds_Search.set("kcomcd", dsPatial.getCellData(row, "kcomcd"));
    ds_Search.set("blno", dsPatial.getCellData(row, "blno"));
    ds_Search.set("mhno", dsPatial.getCellData(row, "mhno"));

    $c.sbm.execute(sbm_AirExportCargoManifestPartial2);

    if (dsPatial.getCellData(dsPatial.getRowPosition(), "flag") == "2") {
        scwin.f_Set("RETRIEVE2");
    } else {
        scwin.f_Set("RETRIEVE");
    }

}

scwin.f_Cancel = function () {
    var dsPatial = ds_AirExportCargoManifestPartial;
    var dsPatial2 = ds_AirExportCargoManifestPartial2;
    if (dsPatial.getCellData(dsPatial.getRowPosition(), "flag") == "2") {
        scwin.f_Set("RETRIEVE");
        $c.gus.cfEnableBtnOnly([btn_cancel]);
        $c.gus.cfDisableBtnOnly([btn_cancel, btn_update, btn_save, btn_delete]);
    } else {
        scwin.f_Set("RETRIEVE");
    }
    if (dsPatial.getRowStatus(dsPatial.getRowPosition()) == "C") {
        dsPatial.removeRow(dsPatial.getRowPosition());
    } else {
        dsPatial.undoRow(dsPatial.getRowPosition());
    }
    for (var i = 0; i < dsPatial2.getTotalRow(); i++) {
        if (dsPatial2.getRowStatus(i) == "C") {
            dsPatial2.removeRow(i);
        } else {
            dsPatial2.undoRow(i);
        }
    }

}

scwin.f_Create = function () {
    if (ds_AirExportCargoManifestPartial.getCellData(ds_AirExportCargoManifestPartial.getRowPosition(), "flag") == "1") {
        $c.gus.cfCopyRecord(gr_AirExportCargoManifestPartial);
        gr_AirExportCargoManifestPartial.setFocusedCell(ds_AirExportCargoManifestPartial.getTotalRow());
    }
    scwin.f_SetDefaultKeyValue(ds_AirExportCargoManifestPartial);
    scwin.f_Set("CREATE");
    gr_AirExportCargoManifestPartial.setFocusedCell(gr_AirExportCargoManifestPartial.getTotalRow() - 1, 0);
}

scwin.f_SetDefaultKeyValue = function (ds) {
    ds.setCellData(ds.getRowPosition(), "updid", scwin.userId);

    if (ds == ds_AirExportCargoManifestPartial2) {
        ds.setCellData(ds.getRowPosition(), "kcomcd", scwin.hid_kcomcd);
        ds.setCellData(ds.getRowPosition(), "mhno", ds_AirExportCargoManifestPartial.getCellData((0, "mhno")));
        ds.setCellData(ds.getRowPosition(), "blno", ds_AirExportCargoManifestPartial.getCellData(0, "blno"));
    }
}

scwin.f_delete = async function () {
    if (await $c.win.confirm("Do you wish delete?")) {  //삭제하시겠습니까?
        var dsPatial = ds_AirExportCargoManifestPartial;
        var dsPatial2 = ds_AirExportCargoManifestPartial2;
        if (dsPatial.getCellData(dsPatial.getRowPosition(), "flag") == "1") {
            dsPatial.modifyRowStatus(dsPatial.getRowPosition(), "D");
        } else {
            $c.gus.cfAlertMsg(MSG_CM_WRN_004, Array("대상"));//삭제할 @이(가) 존재하지 않습니다.
            return;
        }
        if (dsPatial2.getCellData(dsPatial2.getRowPosition(), "flag") == "1") {
            dsPatial.modifyRowStatus(dsPatial.getRowPosition(), "D");
            dsPatial2.setCellData(dsPatial2.getRowPosition(), "seq", "");
        }
        $c.sbm.execute(sbm_delete);
    }
}

scwin.f_Update = function () {
    scwin.f_SetDefaultKeyValue(ds_AirExportCargoManifestPartial);
    scwin.f_Set("UPDATE");
}

scwin.f_save = async function () {
    if (await scwin.f_ReqFieldChk()) {
        $c.gus.cfCopyDataSet(ds_AirExportCargoManifestPartial, ds_AirExportCargoManifestPartialClon);
        $c.gus.cfCopyRecord(gr_AirExportCargoManifestPartialClon);
        $c.sbm.execute(sbm_BLcheck);
    }
}

scwin.f_ReqFieldChk = async function () {
    if (await $c.gus.cfValidate([grp_inputGroup]) == false) {
        return false;
    }

    let validArray = [
        { id: "exno", name: "정정 전 신고번호", mandatory: true },
        { id: "mfpkg", name: "면장수량", mandatory: true },
        { id: "mfwht", name: "면장중량", mandatory: true },
    ];
    ret = await $c.gus.cfValidateGrid(gr_AirExportCargoManifestPartial2, null, null, validArray, "");
    if(!ret) return false;
    return true;
}

scwin.f_Retrieve = function () {
    ds_AirExportCargoManifestPartial.removeAll();
    ds_AirExportCargoManifestPartial2.removeAll();
    if (cnd_ed_blno.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["House B/L No"]); //필수 입력 사항
        cnd_ed_blno.focus();
        return false;
    }

    ds_Search.set("blno", cnd_ed_blno.getValue());
    ds_Search.set("kcomcd", scwin.hid_kcomcd);
    $c.sbm.execute(sbm_retrieve);
}

scwin.f_addRow = function () {
    ds = ds_AirExportCargoManifestPartial2;
    idx = ds.insertRow();
    gr_AirExportCargoManifestPartial2.setFocusedCell(idx, 2);
    scwin.f_SetDefaultKeyValue(ds);
}

scwin.f_deleteRow = function () {
    ds = ds_AirExportCargoManifestPartial2;
    if (ds.getRowStatus(ds_AirExportCargoManifestPartial2.getRowPosition()) == "C") {
        ds.removeRow(ds.getRowPosition());
    } else {
        ds.deleteRow(ds.getRowPosition());
    }
}

scwin.f_undoRow = function () {
    ds = ds_AirExportCargoManifestPartial2;
    if (ds.getRowStatus(ds_AirExportCargoManifestPartial2.getRowPosition()) == "C") {
        ds.removeRow(ds.getRowPosition());
    } else {
        ds.undoRow(ds.getRowPosition());
    }
}

scwin.f_PopUpGrid = function (disGubun, row, pWinCloseTF, pAllSearchTF) {

    switch (disGubun) {
        case "eldpkgut":
            udc_pkg.setSelectId("retrievePackageCode");
            udc_pkg.ilCommonPopUp(scwin.udc_pkg_callbackFunc
                , ds_AirExportCargoManifestPartial2.getCellData(row, "eldpkgut")	 //코드
                , '' 	 //코드명
                , pWinCloseTF		// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '2'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
                , "Code, Name"		// Title순서
                , '80,230'			// 보여주는	각 컬럼들의	폭
                , "3,4,5,6,7,8,9,10"	// 컬럼중에서 숨기는	컬럼 지정
                , null				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null				// POP-UP뛰을때	원도우의	사용자 정의	폭
                , null				// POP-UP뛰을때	우도우의	사용자 정의	높이
                , null				// 윈도우 위치 Y좌표
                , null				// 윈도우 위치 X좌표
                , null				// 중복체크여부	("F")
                , pAllSearchTF		// 전체검색허용여부	("F")
                , "동시포장단위,Code,Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , 'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
            );

            break;

        default:
            break;
    }
}

scwin.udc_pkg_callbackFunc = function (rtnList) {
    $c.gus.cfSetGridReturnValue(rtnList, ds_AirExportCargoManifestPartial2, ds_AirExportCargoManifestPartial2.getRowPosition(), "eldpkgut", "");
}

//---------------------------------------------------------
// 컴포넌트 이벤트
//---------------------------------------------------------   

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function (e) {

};

scwin.sbm_retrieve_submitdone = function (e) {
    if (ds_AirExportCargoManifestPartial.getTotalRow() < 1) {
        ed_totalRow.setValue(0);
        $c.gus.cfAlertMsg("Data not found.");
        return;
    }
    ed_totalRow.setValue(ds_AirExportCargoManifestPartial.getTotalRow());
    if (ds_AirExportCargoManifestPartial.getTotalRow() < 1) {
        scwin.f_Set("INIT");
        return;
    }
    gr_AirExportCargoManifestPartial.setFocusedCell(0, 0);
    // if (ds_AirExportCargoManifestPartial.getCellData(rowIndex, columnInfo)(ds_AirExportCargoManifestPartial.getRowPosition(), "flag") == "2") {
    //     scwin.f_Set("RETRIEVE2");
    // } else {
    scwin.f_Set("RETRIEVE");
    // }
    if (ds_AirExportCargoManifestPartial.getTotalRow() > 0) {
        scwin.f_RetrievePartial2(0);
    }
}

scwin.sbm_AirExportCargoManifestPartial2_submitdone = function (e) {
    ed_totalRow2.setValue(ds_AirExportCargoManifestPartial2.getTotalRow() || "0");
}

scwin.btn_cancel_onclick = function (e) {
    scwin.f_Cancel();
};

scwin.btn_create_onclick = function (e) {
    scwin.f_Create();
};

scwin.btn_update_onclick = function (e) {
    scwin.f_Update();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_save();
};

scwin.btn_delete_onclick = function (e) {
    scwin.f_delete();
};

scwin.sbm_delete_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_004);	// 성공적으로 삭제하였습니다.
    scwin.f_Retrieve();
}

scwin.sbm_BLcheck_submitdone = function (e) {
    if (ds_BLcheck.getTotalRow() > 0) {
        var strError = "";
        for (var i = 0; i < ds_BLcheck.getTotalRow(); i++) {
            strError = strError + ds_BLcheck.getCellData(i, "descnm") + "\n";
        }
        $c.win.alert(strError);
        scwin.f_Cancel();
        return;
    } else {

        var dsPatial = ds_AirExportCargoManifestPartial;
        var dsPatial2 = ds_AirExportCargoManifestPartial2;

        if (dsPatial.getCellData(dsPatial.getRowPosition(), "flag") == "2") {
            dsPatial.modifyRowStatus(dsPatial.getRowPosition(), "C");
        }
        if (dsPatial2.getCellData(dsPatial2.getRowPosition(), "flag") == "2") {
            for (var i = 0; i < dsPatial2.getTotalRow(); i++) {
                dsPatial2.modifyRowStatus(i, "C");
            }
        }

        $c.sbm.execute(sbm_save);
    }
}

scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
}

scwin.gr_AirExportCargoManifestPartial_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.f_RetrievePartial2(rowIndex);
};

scwin.gr_AirExportCargoManifestPartial2_ontextimageclick = function (rowIndex, columnIndex) {
    scwin.f_PopUpGrid("eldpkgut", rowIndex, "F", "T");
};

scwin.gr_AirExportCargoManifestPartial2_onviewchange = function (info) {
    if (info.colId != "eldpkgut") return;
    scwin.f_PopUpGrid("eldpkgut", info.rowIndex, "T", "T");
};

scwin.oneditkeyup = function (info, e) {
    this.setValue(e.target.value.toUpperCase());
};
